+const sharedToolbars = new WeakMap<HTMLElement, SharedToolbar>();
+
+function getSharedToolbar(container: HTMLElement) {
+  let toolbar = sharedToolbars.get(container);
+  if (toolbar == null) {
+    toolbar = new SharedToolbar(container);
+    sharedToolbars.set(container, toolbar);
+  }
+  return toolbar;
+}
+
+class SharedToolbar {
+  active: Toolbar | null = null;
+  private toolbars = new Set<Toolbar>();
+  updateListeners = new Set<() => void>();
+  controlListeners = new Set<(controls: HTMLElement[]) => void>();
+  private uiClaimed = false;
+  private observer: MutationObserver;
+
+  constructor(private container: HTMLElement) {
+    container.addEventListener('click', (event) => this.handle(event));
+    container.addEventListener('change', (event) => this.handle(event));
+    container.addEventListener('mousedown', (event) => {
+      if ((event.target as Element).closest('button')) event.preventDefault();
+    });
+    this.observer = new MutationObserver((records) => {
+      const controls = records.flatMap((record) =>
+        Array.from(record.addedNodes).flatMap((node) =>
+          node instanceof HTMLElement
+            ? [node, ...Array.from(node.querySelectorAll<HTMLElement>('button, select'))]
+            : [],
+        ),
+      );
+      if (controls.length > 0) this.controlsChanged(controls);
+    });
+    this.observer.observe(container, { childList: true, subtree: true });
+  }
+
+  add(toolbar: Toolbar) {
+    this.toolbars.add(toolbar);
+    this.controlsChanged();
+  }
+
+  claimUI() {
+    if (this.uiClaimed) return false;
+    this.uiClaimed = true;
+    return true;
+  }
+
+  activate(toolbar: Toolbar) {
+    if (!this.isLive(toolbar)) return;
+    this.active = toolbar;
+    this.update();
+  }
+
+  controlsChanged(controls?: HTMLElement[]) {
+    if (controls != null) this.controlListeners.forEach((listener) => listener(controls));
+    this.update();
+  }
+
+  update() {
+    if (this.active != null && !this.isLive(this.active)) this.active = null;
+    if (this.active == null) {
+      this.toolbars.forEach((toolbar) => toolbar.update(null));
+      return;
+    }
+    const [range] = this.active.quill.selection.getRange();
+    this.active.update(range);
+    this.updateListeners.forEach((listener) => listener());
+  }
+
+  private handle(event: Event) {
+    const input = (event.target as Element).closest<HTMLElement>('button, select');
+    if (input == null || !this.container.contains(input)) return;
+    if (this.active == null || !this.isLive(this.active) || !this.active.quill.isEnabled()) {
+      event.preventDefault();
+      this.update();
+      return;
+    }
+    this.active.handle(input, event);
+  }
+
+  private isLive(toolbar: Toolbar) {
+    return this.toolbars.has(toolbar) && document.body.contains(toolbar.quill.root);
+  }
